        w2 = MPN_RIGHT_SHIFT_LOW(y3, y2, b);
        w3 = MPN_RIGHT_SHIFT_LOW(y4, y3, b);
        w4 = MPN_RIGHT_SHIFT_LOW(UWORD(0), y4, b);
