        y0 = (y0 & bw) | (e0 & m);
        y1 = (y1 & bw) | (e1 & m);
        y2 = (y2 & bw) | (e2 & m);
        y3 = (y3 & bw) | (e3 & m);
        y4 = (y4 & bw) | (e4 & m);
